function makeArticle(def: NewArticleDef): Article {
  const base = new Date("2026-04-11");
  base.setDate(base.getDate() + def.day - 1);
  const publishDate = base.toISOString().split("T")[0];

  return {
    slug: def.slug,
    title: def.en.title,
    category: def.category,
    type: def.type,
    description: def.en.description,
    intro: def.en.intro,
    keywords: def.en.keywords,
    publishDate,
    steps: enSteps[def.type],
    faqs: [],
    relatedSlugs: [],
    youtubeSearch: `https://www.youtube.com/results?search_query=${encodeURIComponent(def.en.title)}`,
    translations: {
      ar: { title: def.ar.title, description: def.ar.description, intro: def.ar.intro, keywords: def.ar.keywords },
      es: { title: def.es.title, description: def.es.description, intro: def.es.intro, keywords: def.es.keywords },
    },
  };
}

export const newArticles: Article[] = defs.map(makeArticle);
